{
  "name": "Ingrediently",
  "description": "A minimalist recipe generator powered by Gemini. Enter ingredients, choose a cuisine, and get a beautiful, step-by-step recipe card."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Ingredient {
  name: string;
  amount: string;
}

export interface Step {
  stepNumber: number;
  instruction: string;
  timerSeconds?: number; // Optional timer for this step
}

export interface Recipe {
  title: string;
  description: string;
  cuisine: string;
  prepTimeMinutes: number;
  cookTimeMinutes: number;
  servings: number;
  caloriesPerServing: number;
  ingredients: Ingredient[];
  steps: Step[];
}

export enum CuisineType {
  Italian = "Italian",
  Mexican = "Mexican",
  Thai = "Thai",
  Japanese = "Japanese",
  Indian = "Indian",
  Mediterranean = "Mediterranean",
  American = "American",
  French = "French",
  Vegetarian = "Vegetarian",
  Vegan = "Vegan"
}

export interface GenerateRecipeParams {
  ingredients: string[];
  cuisine: string;
  isMock?: boolean;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Recipe, GenerateRecipeParams } from "../types";

// Mock data for fallback/testing
const MOCK_RECIPE: Recipe = {
  title: "Rustic Sage & Mushroom Pasta",
  description: "A comforting, creamy pasta dish highlighting earthy mushrooms and fresh aromatic sage.",
  cuisine: "Italian",
  prepTimeMinutes: 15,
  cookTimeMinutes: 20,
  servings: 2,
  caloriesPerServing: 450,
  ingredients: [
    { name: "Pasta (Fettuccine or Tagliatelle)", amount: "200g" },
    { name: "Mushrooms (Cremini or Button)", amount: "250g" },
    { name: "Garlic", amount: "2 cloves, minced" },
    { name: "Fresh Sage Leaves", amount: "10-12 leaves" },
    { name: "Heavy Cream", amount: "1/2 cup" },
    { name: "Parmesan Cheese", amount: "1/4 cup, grated" },
    { name: "Butter", amount: "2 tbsp" }
  ],
  steps: [
    { stepNumber: 1, instruction: "Boil a large pot of salted water. Add pasta and cook until al dente.", timerSeconds: 600 },
    { stepNumber: 2, instruction: "While pasta cooks, heat butter in a large skillet over medium heat. Add sage leaves and fry for 1-2 minutes until crisp. Remove sage and set aside." },
    { stepNumber: 3, instruction: "In the same skillet, add sliced mushrooms. Sauté until browned and moisture evaporates.", timerSeconds: 300 },
    { stepNumber: 4, instruction: "Add minced garlic to the mushrooms and cook for 30 seconds until fragrant." },
    { stepNumber: 5, instruction: "Pour in the heavy cream and simmer gently for 2-3 minutes to thicken slightly.", timerSeconds: 120 },
    { stepNumber: 6, instruction: "Toss the cooked pasta directly into the sauce. Stir in parmesan cheese and half the crispy sage." },
    { stepNumber: 7, instruction: "Serve immediately, topped with remaining crispy sage and black pepper." }
  ]
};

const recipeSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    description: { type: Type.STRING },
    cuisine: { type: Type.STRING },
    prepTimeMinutes: { type: Type.INTEGER },
    cookTimeMinutes: { type: Type.INTEGER },
    servings: { type: Type.INTEGER },
    caloriesPerServing: { type: Type.INTEGER },
    ingredients: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          amount: { type: Type.STRING }
        },
        required: ["name", "amount"]
      }
    },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          stepNumber: { type: Type.INTEGER },
          instruction: { type: Type.STRING },
          timerSeconds: { type: Type.INTEGER, description: "Optional duration in seconds if this step requires a timer (e.g. boil for 10 mins)" }
        },
        required: ["stepNumber", "instruction"]
      }
    }
  },
  required: ["title", "description", "cuisine", "ingredients", "steps", "prepTimeMinutes", "cookTimeMinutes"]
};

export const generateRecipe = async ({ ingredients, cuisine, isMock }: GenerateRecipeParams): Promise<Recipe> => {
  if (isMock) {
    return new Promise((resolve) => setTimeout(() => resolve(MOCK_RECIPE), 2000));
  }

  if (!process.env.API_KEY) {
    console.warn("No API Key found. Returning mock data.");
    return MOCK_RECIPE;
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Create a delicious ${cuisine} recipe using the following ingredients: ${ingredients.join(", ")}.
    You may assume basic pantry staples (oil, salt, pepper, water) are available.
    Be creative but realistic.
    Ensure the instructions are clear and step-by-step.
    If a step involves a specific duration (like boiling or baking), include the 'timerSeconds' field.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as Recipe;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, KeyboardEvent } from 'react';
import { X, Plus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface IngredientInputProps {
  ingredients: string[];
  setIngredients: (ingredients: string[]) => void;
}

const IngredientInput: React.FC<IngredientInputProps> = ({ ingredients, setIngredients }) => {
  const [inputValue, setInputValue] = useState('');

  const addIngredient = () => {
    const trimmed = inputValue.trim();
    if (trimmed && !ingredients.includes(trimmed)) {
      setIngredients([...ingredients, trimmed]);
      setInputValue('');
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      addIngredient();
    }
  };

  const removeIngredient = (ingredientToRemove: string) => {
    setIngredients(ingredients.filter(ing => ing !== ingredientToRemove));
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div className="relative">
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Type an ingredient and press Enter (e.g. Chicken, Basil)..."
          className="w-full px-6 py-4 text-lg bg-white rounded-2xl shadow-sm border border-cream-dark focus:border-sage focus:ring-2 focus:ring-sage/20 outline-none transition-all placeholder:text-gray-400 text-charcoal"
        />
        <button
          onClick={addIngredient}
          disabled={!inputValue.trim()}
          className="absolute right-3 top-1/2 -translate-y-1/2 p-2 bg-sage text-white rounded-xl hover:bg-sage-dark transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Plus size={20} />
        </button>
      </div>

      <div className="mt-4 flex flex-wrap gap-2 min-h-[40px]">
        <AnimatePresence>
          {ingredients.map((ing) => (
            <motion.span
              key={ing}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              className="inline-flex items-center px-4 py-2 rounded-full bg-white border border-sage/30 text-charcoal shadow-sm"
            >
              {ing}
              <button
                onClick={() => removeIngredient(ing)}
                className="ml-2 p-0.5 text-sage hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
              >
                <X size={14} />
              </button>
            </motion.span>
          ))}
        </AnimatePresence>
        {ingredients.length === 0 && (
          <span className="text-gray-400 italic text-sm py-2">No ingredients added yet.</span>
        )}
      </div>
    </div>
  );
};

export default IngredientInput;

