import React, { useState } from 'react';
import { Loader2, Sparkles, ChefHat, LayoutGrid, Send, Wand2, History, RefreshCcw, Globe } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import IngredientInput from './components/IngredientInput';
import CuisineSelector from './components/CuisineSelector';
import DietarySelector from './components/DietarySelector';
import CommonIngredientsModal from './components/CommonIngredientsModal';
import HistoryDrawer from './components/HistoryDrawer';
import RecipeCard from './components/RecipeCard';
import { Recipe, CuisineType, HistoryItem, Language } from './types';
import { generateRecipe, modifyRecipe } from './services/geminiService';

const App: React.FC = () => {
  const [ingredients, setIngredients] = useState<string[]>([]);
  const [selectedCuisine, setSelectedCuisine] = useState<string>(CuisineType.Italian);
  const [dietaryRestrictions, setDietaryRestrictions] = useState<string[]>([]);
  const [isIngredientsModalOpen, setIsIngredientsModalOpen] = useState(false);
  const [selectedLanguage, setSelectedLanguage] = useState<Language>('English');

  // Recipe & History State
  const [recipe, setRecipe] = useState<Recipe | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Modification State
  const [modificationPrompt, setModificationPrompt] = useState('');
  const [isModifying, setIsModifying] = useState(false);

  // Helper to add to history
  const addToHistory = (newRecipe: Recipe, type: 'generated' | 'modification', prompt?: string) => {
    const newItem: HistoryItem = {
      id: crypto.randomUUID(),
      recipe: newRecipe,
      timestamp: Date.now(),
      type,
      prompt
    };
    setHistory(prev => [newItem, ...prev]);
  };

  const toggleDietaryRestriction = (restriction: string) => {
    setDietaryRestrictions(prev => 
      prev.includes(restriction) 
        ? prev.filter(r => r !== restriction) 
        : [...prev, restriction]
    );
  };

  const handleGenerate = async () => {
    if (ingredients.length === 0) return;

    setLoading(true);
    setError(null);
    setRecipe(null);
    setModificationPrompt('');

    try {
      const result = await generateRecipe({ 
        ingredients, 
        cuisine: selectedCuisine,
        dietaryRestrictions,
        avoidTitles: [],
        language: selectedLanguage,
        isMock: false 
      });
      setRecipe(result);
      addToHistory(result, 'generated');
    } catch (err) {
      setError("Failed to generate recipe. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleRegenerate = async () => {
    if (ingredients.length === 0) return;

    // Ensure we are using the cuisine of the currently displayed recipe if possible
    const cuisineToUse = recipe ? recipe.cuisine : selectedCuisine;

    setLoading(true);
    setError(null);
    setRecipe(null);
    setModificationPrompt('');

    // Collect titles to avoid from history to ensure variety
    const avoidTitles = history.map(h => h.recipe.title);

    try {
      const result = await generateRecipe({ 
        ingredients, 
        cuisine: cuisineToUse,
        dietaryRestrictions,
        avoidTitles,
        language: selectedLanguage,
        isMock: false
      });
      setRecipe(result);
      addToHistory(result, 'generated');
    } catch (err) {
      setError("Failed to generate recipe. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleModify = async () => {
    if (!recipe || !modificationPrompt.trim()) return;

    setIsModifying(true);
    setError(null);

    try {
      const result = await modifyRecipe(recipe, modificationPrompt, selectedLanguage, false);
      setRecipe(result);
      addToHistory(result, 'modification', modificationPrompt);
      setModificationPrompt('');
    } catch (err) {
      setError("Failed to modify recipe. Please try again.");
    } finally {
      setIsModifying(false);
    }
  };

  const handleSelectHistoryItem = (item: HistoryItem) => {
    setRecipe(item.recipe);
    // Sync the inputs with the history item to make "Generate Another" work intuitively
    setIngredients(item.recipe.ingredients.map(i => i.name.split('(')[0].trim())); 
    // Try to match cuisine if it exists in our list, otherwise keep it as string
    setSelectedCuisine(item.recipe.cuisine);

    setIsHistoryOpen(false);
  };

  return (
    <div className="min-h-screen bg-cream selection:bg-sage/20 selection:text-charcoal font-sans pb-20">

      {/* Header */}
      <header className="sticky top-0 z-40 bg-cream/80 backdrop-blur-md border-b border-cream-dark">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-charcoal hover:text-sage transition-colors cursor-pointer" onClick={() => window.location.reload()}>
            <span className="font-serif font-bold text-xl tracking-tight">Ingrediently</span>
          </div>

          <div className="flex items-center gap-3">
             {/* Language Selector */}
             <div className="relative group hidden sm:block">
               <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-white border border-cream-dark text-xs font-medium text-charcoal hover:border-sage transition-colors cursor-pointer">
                  <Globe size={14} />
                  <span>{selectedLanguage}</span>
               </div>
               <div className="absolute top-full right-0 mt-2 w-32 bg-white rounded-xl shadow-lg border border-cream-dark overflow-hidden hidden group-hover:block">
                 {['English', 'Spanish', 'Russian'].map((lang) => (
                    <button
                      key={lang}
                      onClick={() => setSelectedLanguage(lang as Language)}
                      className={`w-full text-left px-4 py-2 text-xs hover:bg-cream transition-colors ${selectedLanguage === lang ? 'font-bold text-sage' : 'text-charcoal'}`}
                    >
                      {lang}
                    </button>
                 ))}
               </div>
             </div>

            <button
              onClick={() => setIsHistoryOpen(true)}
              className="p-2 text-charcoal hover:bg-white hover:text-sage rounded-full transition-all border border-transparent hover:border-cream-dark relative"
              title="History"
            >
              <History size={20} />
              {history.length > 0 && (
                <span className="absolute top-1 right-1 w-2 h-2 bg-sage rounded-full" />
              )}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 pt-12">

        {/* Hero Section */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-12"
        >
          <h1 className="font-serif text-4xl md:text-5xl font-bold text-charcoal mb-4">
            What's in your pantry?
          </h1>
          <p className="text-gray-500 text-lg max-w-xl mx-auto">
            Enter your leftover ingredients, pick a style, and let AI craft the perfect recipe for you.
          </p>
        </motion.div>

        {/* Controls Section */}
        <div className="space-y-10 mb-16">
          <section className="flex flex-col items-center gap-4">
            <IngredientInput ingredients={ingredients} setIngredients={setIngredients} />
            <button
              onClick={() => setIsIngredientsModalOpen(true)}
              className="flex items-center gap-2 text-sage-dark font-medium text-sm hover:bg-white hover:shadow-sm px-4 py-2 rounded-full transition-all border border-transparent hover:border-sage/20"
            >
              <LayoutGrid size={16} />
              Browse Common Ingredients
            </button>
          </section>

          <div className="grid md:grid-cols-1 gap-8">
            <section className="space-y-3">
              <h3 className="text-sm font-bold text-charcoal uppercase tracking-wider text-center md:text-left">
                Select Cuisine
              </h3>
              <CuisineSelector 
                selectedCuisine={selectedCuisine} 
                onSelect={setSelectedCuisine} 
              />
            </section>

            <section className="space-y-3">
              <h3 className="text-sm font-bold text-charcoal uppercase tracking-wider text-center md:text-left">
                Dietary Restrictions
              </h3>
              <DietarySelector
                selectedRestrictions={dietaryRestrictions}
                toggleRestriction={toggleDietaryRestriction}
              />
            </section>
          </div>

          <div className="flex justify-center pt-4">
            <button
              onClick={handleGenerate}
              disabled={ingredients.length === 0 || loading}
              className={`
                group relative flex items-center gap-3 px-8 py-4 rounded-2xl font-bold text-lg shadow-lg transition-all duration-300
                ${ingredients.length === 0 || loading 
                  ? 'bg-gray-200 text-gray-400 cursor-not-allowed shadow-none' 
                  : 'bg-charcoal text-white hover:bg-sage hover:shadow-sage/30 hover:-translate-y-1'
                }
              `}
            >
              {loading ? (
                <>
                  <Loader2 size={24} className="animate-spin" />
                  <span>Chef is cooking...</span>
                </>
              ) : (
                <>
                  <Sparkles size={20} className={ingredients.length > 0 ? "text-yellow-200" : ""} />
                  <span>Generate Recipe</span>
                </>
              )}
            </button>
          </div>
        </div>

        {/* Error Message */}
        <AnimatePresence>
          {error && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="bg-red-50 text-red-500 p-4 rounded-xl text-center mb-8 border border-red-100"
            >
              {error}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Recipe Display */}
        <AnimatePresence mode="wait">
          {recipe && !loading && !isModifying && (
             <div className="mb-20 space-y-8">
               <RecipeCard recipe={recipe} />

               {/* Modification & Regenerate Actions */}
               <div className="grid gap-6">
                 {/* Modification Interface */}
                 <motion.div 
                   initial={{ opacity: 0, y: 10 }}
                   animate={{ opacity: 1, y: 0 }}
                   className="bg-white rounded-2xl p-6 shadow-lg border border-cream-dark"
                 >
                   <h3 className="font-serif text-lg font-bold text-charcoal mb-3 flex items-center gap-2">
                     <Wand2 size={18} className="text-sage" />
                     Tweak this recipe
                   </h3>
                   <div className="flex flex-col sm:flex-row gap-3">
                     <input
                       type="text"
                       value={modificationPrompt}
                       onChange={(e) => setModificationPrompt(e.target.value)}
                       placeholder="e.g. 'Make it spicy', 'Use less oil', 'Add more protein'..."
                       className="flex-1 px-4 py-3 rounded-xl border border-cream-dark focus:border-sage focus:ring-1 focus:ring-sage outline-none bg-cream/50"
                       onKeyDown={(e) => e.key === 'Enter' && handleModify()}
                     />
                     <button 
                       onClick={handleModify}
                       disabled={!modificationPrompt.trim()}
                       className="bg-charcoal text-white px-6 py-3 rounded-xl font-medium hover:bg-sage transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 justify-center"
                     >
                       <span>Refine</span>
                       <Send size={16} />
                     </button>
                   </div>
                 </motion.div>

                 {/* Regenerate Button */}
                 <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    className="flex justify-center"
                 >
                    <button
                        onClick={handleRegenerate}
                        className="flex items-center gap-2 text-charcoal bg-white border border-cream-dark hover:border-sage hover:text-sage px-6 py-3 rounded-xl transition-all shadow-sm hover:shadow-md font-medium"
                    >
                        <RefreshCcw size={18} />
                        Generate Another {recipe.cuisine} Dish
                    </button>
                 </motion.div>
               </div>
             </div>
          )}

          {/* Loading Skeleton / Illustration */}
          {(loading || isModifying) && (
             <motion.div 
               initial={{ opacity: 0 }} 
               animate={{ opacity: 1 }} 
               exit={{ opacity: 0 }}
               className="flex flex-col items-center justify-center py-20 text-sage/50"
             >
                <div className="relative">
                  <div className="absolute inset-0 animate-ping rounded-full bg-sage/20"></div>
                  <ChefHat size={64} className="relative z-10 animate-bounce text-sage" />
                </div>
                <p className="mt-8 text-lg font-serif text-charcoal">
                  {isModifying ? "Adjusting the recipe..." : "Curating flavors..."}
                </p>
             </motion.div>
          )}
        </AnimatePresence>

      </main>

      {/* Modals & Drawers */}
      <CommonIngredientsModal 
        isOpen={isIngredientsModalOpen} 
        onClose={() => setIsIngredientsModalOpen(false)}
        ingredients={ingredients}
        setIngredients={setIngredients}
      />

      <HistoryDrawer 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={history}
        onSelectRecipe={handleSelectHistoryItem}
      />
    </div>
  );
};

export default App;

import React, { useState, KeyboardEvent } from 'react';
import { X, Plus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface IngredientInputProps {
  ingredients: string[];
  setIngredients: (ingredients: string[]) => void;
  placeholder: string;
  emptyText: string;
}

const IngredientInput: React.FC<IngredientInputProps> = ({ ingredients, setIngredients, placeholder, emptyText }) => {
  const [inputValue, setInputValue] = useState('');

  const addIngredient = () => {
    const trimmed = inputValue.trim();
    if (trimmed && !ingredients.includes(trimmed)) {
      setIngredients([...ingredients, trimmed]);
      setInputValue('');
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      addIngredient();
    }
  };

  const removeIngredient = (ingredientToRemove: string) => {
    setIngredients(ingredients.filter(ing => ing !== ingredientToRemove));
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div className="relative">
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          className="w-full px-6 py-4 text-lg bg-white rounded-2xl shadow-sm border border-cream-dark focus:border-sage focus:ring-2 focus:ring-sage/20 outline-none transition-all placeholder:text-gray-400 text-charcoal"
        />
        <button
          onClick={addIngredient}
          disabled={!inputValue.trim()}
          className="absolute right-3 top-1/2 -translate-y-1/2 p-2 bg-sage text-white rounded-xl hover:bg-sage-dark transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Plus size={20} />
        </button>
      </div>

      <div className="mt-4 flex flex-wrap gap-2 min-h-[40px]">
        <AnimatePresence>
          {ingredients.map((ing) => (
            <motion.span
              key={ing}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              className="inline-flex items-center px-4 py-2 rounded-full bg-white border border-sage/30 text-charcoal shadow-sm"
            >
              {ing}
              <button
                onClick={() => removeIngredient(ing)}
                className="ml-2 p-0.5 text-sage hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
              >
                <X size={14} />
              </button>
            </motion.span>
          ))}
        </AnimatePresence>
        {ingredients.length === 0 && (
          <span className="text-gray-400 italic text-sm py-2">{emptyText}</span>
        )}
      </div>
    </div>
  );
};

export default IngredientInput;

import React, { useRef, useEffect } from 'react';
import { CuisineType } from '../types';

interface CuisineSelectorProps {
  selectedCuisine: string;
  onSelect: (cuisine: string) => void;
  translations: Record<string, string>;
}

const CuisineSelector: React.FC<CuisineSelectorProps> = ({ selectedCuisine, onSelect, translations }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const itemsRaw = Object.values(CuisineType);
  // Create 3 sets for infinite scrolling: [Buffer, Main, Buffer]
  const items = [...itemsRaw, ...itemsRaw, ...itemsRaw];

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;

    // Center the scroll view initially to the middle set
    const initializeScroll = () => {
        if (el.scrollWidth > el.clientWidth) {
            const singleSetWidth = el.scrollWidth / 3;
            el.scrollLeft = singleSetWidth;
        }
    }

    // Attempt initialization after layout
    initializeScroll();
    setTimeout(initializeScroll, 50);

    const handleWheel = (e: WheelEvent) => {
      e.preventDefault();
      el.scrollLeft += e.deltaY; 
    };

    el.addEventListener('wheel', handleWheel, { passive: false });

    return () => {
      el.removeEventListener('wheel', handleWheel);
    };
  }, []);

  const handleScroll = () => {
    const el = scrollRef.current;
    if (!el) return;

    const singleSetWidth = el.scrollWidth / 3;

    if (el.scrollLeft < singleSetWidth) {
        el.scrollLeft += singleSetWidth;
    } 
    else if (el.scrollLeft >= singleSetWidth * 2) {
        el.scrollLeft -= singleSetWidth;
    }
  };

  return (
    <div 
        ref={scrollRef}
        onScroll={handleScroll}
