            >
              {isBusy ? (
                <>
                  <Loader2 size={24} className="animate-spin" />
                  <span>{loadingLabel}</span>
                </>
              ) : (
                <>
                  <Sparkles size={20} className={ingredients.length > 0 ? "text-yellow-200" : ""} />
                  <span>{t.generate}</span>
